import React, { useEffect, useState, useRef } from 'react';
import { getMT5Candles, getMT5Tick, getMT5Account } from '../services/api';
import TradingPanel from '../components/TradingPanel';
import Navbar from '../components/Navbar';
import { createChart } from 'lightweight-charts';
import './GoldChart.css';

function GoldChart() {
  const [timeframe, setTimeframe] = useState('H1');
  const [currentTick, setCurrentTick] = useState(null);
  const [accountInfo, setAccountInfo] = useState(null);
  const [candles, setCandles] = useState([]);
  const chartContainerRef = useRef(null);
  const chartRef = useRef(null);
  const candlestickSeriesRef = useRef(null);

  const timeframes = ['M1', 'M5', 'M15', 'M30', 'H1', 'H4', 'D1'];

  const validateAndFormatCandles = (rawCandles) => {
    if (!Array.isArray(rawCandles)) {
      console.warn('Invalid candles data: not an array');
      return [];
    }

    const validCandles = rawCandles.map(c => {
      // Ensure time is a number (Unix seconds)
      let time = c.time;
      if (typeof time === 'string') {
        // Convert ISO string to Unix seconds if needed
        time = Math.floor(new Date(time).getTime() / 1000);
      } else if (typeof time === 'number' && time > 1e12) {
        // If it's in milliseconds, convert to seconds
        time = Math.floor(time / 1000);
      }

      return {
        time: Number(time),
        open: Number(c.open),
        high: Number(c.high),
        low: Number(c.low),
        close: Number(c.close)
      };
    }).filter(c => {
      // Filter out invalid candles
      return (
        typeof c.time === 'number' && !isNaN(c.time) &&
        typeof c.open === 'number' && !isNaN(c.open) &&
        typeof c.high === 'number' && !isNaN(c.high) &&
        typeof c.low === 'number' && !isNaN(c.low) &&
        typeof c.close === 'number' && !isNaN(c.close)
      );
    });

    // Sort by time ascending
    validCandles.sort((a, b) => a.time - b.time);

    console.log('Validated and formatted candles:', validCandles);
    return validCandles;
  };

  useEffect(() => {
    const fetchCandles = async () => {
      try {
        const candleData = await getMT5Candles('XAUUSD', timeframe, 500);
        console.log('Received raw candles from API:', candleData);
        const validatedCandles = validateAndFormatCandles(candleData);
        setCandles(validatedCandles);
      } catch (error) {
        console.error('Failed to fetch candles:', error);
        setCandles([]);
      }
    };
    fetchCandles();
  }, [timeframe]);

  useEffect(() => {
    if (!chartContainerRef.current) return;

    const chart = createChart(chartContainerRef.current, {
      width: chartContainerRef.current.clientWidth,
      height: 500,
      layout: {
        background: { color: '#222' },
        textColor: '#DDD',
      },
      grid: {
        vertLines: { color: '#444' },
        horzLines: { color: '#444' },
      },
      crosshair: {
        mode: 1,
      },
      rightPriceScale: {
        borderColor: '#444',
      },
      timeScale: {
        borderColor: '#444',
      },
    });

    const candlestickSeries = chart.addCandlestickSeries({
      upColor: '#26a69a',
      downColor: '#ef5350',
      borderUpColor: '#26a69a',
      borderDownColor: '#ef5350',
      wickUpColor: '#26a69a',
      wickDownColor: '#ef5350',
    });

    chartRef.current = chart;
    candlestickSeriesRef.current = candlestickSeries;

    const handleResize = () => {
      if (chartContainerRef.current && chart) {
        chart.applyOptions({ width: chartContainerRef.current.clientWidth });
      }
    };
    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      chart.remove();
    };
  }, []);

  useEffect(() => {
    if (candlestickSeriesRef.current && candles.length > 0) {
      // Lightweight Charts expects time in seconds since epoch for candlesticks
      const formattedData = candles.map(c => ({
        time: c.time, // Backend already returns seconds since epoch
        open: c.open,
        high: c.high,
        low: c.low,
        close: c.close
      }));
      candlestickSeriesRef.current.setData(formattedData);
      if (chartRef.current) {
        chartRef.current.timeScale().fitContent();
      }
    }
  }, [candles]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const tick = await getMT5Tick('XAUUSD');
        setCurrentTick(tick);

        const account = await getMT5Account();
        setAccountInfo(account);
      } catch (error) {
        console.error('Failed to fetch data:', error);
      }
    };

    fetchData();
    const interval = setInterval(fetchData, 1000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="gold-chart">
      <Navbar />
      <div className="chart-header">
        <h1>Gold Chart</h1>
        <div className="timeframe-selector">
          {timeframes.map(tf => (
            <button
              key={tf}
              className={`timeframe-btn ${timeframe === tf ? 'active' : ''}`}
              onClick={() => setTimeframe(tf)}
            >
              {tf}
            </button>
          ))}
        </div>
      </div>
      
      <div className="chart-container">
        <div className="chart-main" ref={chartContainerRef} style={{ width: '100%', minHeight: '500px', height: '100%' }} />
        <div className="chart-sidebar">
          <TradingPanel 
            currentTick={currentTick} 
            accountInfo={accountInfo}
            onTradeSuccess={() => {}}
          />
        </div>
      </div>
    </div>
  );
}

export default GoldChart;
